external_knowledge:
- 'Longer songs' refers to songs with a duration of more than 5 minutes; 
- 'Shorter versions' refers to songs with the same artist and title but with a duration of less than 5 minutes; 
- 'Non-single songs' are songs where 'is_single' is 0.

sql:
SELECT song_id
FROM song_rankings
WHERE peak_rank = (SELECT MAX(peak_rank) FROM song_rankings);
